const raw = $input.first().json.data;
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = { seen: [] };
}
return [{ json: { seenUrls: parsed.seen || [] } }];

return $input.all().map(item => ({
  json: {
    title: item.json.title || '',
    url: item.json.link || '',
    thumbnail: item.json.enclosure?.url || item.json['media:content']?.url || '',
    source: 'Siteinspire',
    sourceColor: '#0F766E',
    date: item.json.pubDate || new Date().toISOString()
  }
}));

const items = $input.first().json.items || [];
const cheerio = require ? null : null;
return items.slice(0, 10).map((html, i) => {
  const titleMatch = html.match(/<h2[^>]*>([^<]+)<\/h2>/);
  const urlMatch = html.match(/href="(\/websites\/[^"]+)"/);
  const imgMatch = html.match(/src="([^"]+\.(?:jpg|png|webp))"/);
  return {
    json: {
      title: titleMatch ? titleMatch[1].trim() : `Awwwards Site ${i+1}`,
      url: urlMatch ? `https://www.awwwards.com${urlMatch[1]}` : 'https://www.awwwards.com/websites/',
      thumbnail: imgMatch ? imgMatch[1] : '',
      source: 'Awwwards',
      sourceColor: '#B45309',
      date: new Date().toISOString()
    }
  };
});

const html = $input.first().json.data || '';
const items = [];
const regex = /data-template-id="([^"]+)"[\s\S]*?alt="([^"]+)"[\s\S]*?src="([^"]+framer\.com[^"]+)"/g;
let match;
while ((match = regex.exec(html)) !== null && items.length < 8) {
  items.push({
    json: {
      title: match[2] || `Framer Template`,
      url: `https://www.framer.com/marketplace/templates/${match[1]}/`,
      thumbnail: match[3],
      source: 'Framer',
      sourceColor: '#1A56DB',
      date: new Date().toISOString()
    }
  });
}
return items.length > 0 ? items : [{ json: { title: 'Check Framer Marketplace', url: 'https://www.framer.com/marketplace/', thumbnail: '', source: 'Framer', sourceColor: '#1A56DB', date: new Date().toISOString() } }];

const seenUrls = $('Parse Seen JSON').first().json.seenUrls || [];
const allItems = $input.all();
const newItems = allItems.filter(item => {
  const url = item.json.url || '';
  return url && !seenUrls.includes(url);
});
if (newItems.length === 0) {
  return [{ json: { empty: true, message: 'No new entries found today.' } }];
}
return newItems;

const items = $input.all();
const webhookBase = 'http://YOUR_DROPLET_IP:5678/webhook/uix-approve';
const today = new Date().toLocaleDateString('en-US', { weekday:'long', year:'numeric', month:'long', day:'numeric' });

let cards = items.map(item => {
  const { title, url, thumbnail, source, sourceColor } = item.json;
  const approveUrl = `${webhookBase}?url=${encodeURIComponent(url)}&source=${encodeURIComponent(source)}`;
  const img = thumbnail ? `<img src="${thumbnail}" style="width:100%;height:160px;object-fit:cover;border-radius:4px;" />` : `<div style="width:100%;height:160px;background:#1A1A1A;border-radius:4px;display:flex;align-items:center;justify-content:center;"><span style="color:#555;">No preview</span></div>`;
  return `
  <div style="background:#111;border:1px solid #2A2A2A;border-radius:8px;padding:16px;margin-bottom:16px;">
    ${img}
    <div style="margin-top:12px;">
      <span style="background:${sourceColor};color:#fff;font-size:11px;padding:2px 8px;border-radius:3px;font-family:monospace;">${source.toUpperCase()}</span>
      <h3 style="color:#F0F0F0;margin:8px 0 4px;font-family:Arial;font-size:16px;">${title}</h3>
      <a href="${url}" style="color:#888;font-size:13px;">${url}</a>
    </div>
    <a href="${approveUrl}" style="display:inline-block;margin-top:12px;background:#FFFFFF;color:#000;padding:8px 20px;border-radius:4px;text-decoration:none;font-family:Arial;font-size:14px;font-weight:bold;">APPROVE →</a>
  </div>`;
}).join('');

const html = `
<!DOCTYPE html><html><body style="background:#0A0A0A;padding:32px;font-family:Arial,sans-serif;max-width:640px;margin:0 auto;">
<div style="border-bottom:2px solid #1D3557;padding-bottom:16px;margin-bottom:24px;">
  <span style="color:#F0F0F0;font-size:24px;font-weight:bold;">UIX</span>
  <span style="color:#888;font-size:14px;margin-left:12px;">Gallery Crawler — ${items.length} new site${items.length > 1 ? 's' : ''}</span>
  <p style="color:#555;font-size:13px;margin:4px 0 0;">${today}</p>
</div>
${cards}
<p style="color:#333;font-size:12px;margin-top:24px;">Click APPROVE on any site to trigger content generation and add it to your UIX gallery queue.</p>
</body></html>`;

return [{ json: { html, subject: `UIX Gallery Alert — ${items.length} new site${items.length>1?'s':''} found — ${today}` } }];

const seenUrls = $('Parse Seen JSON').first().json.seenUrls || [];
const newUrls = $('Filter New Entries Only').all().map(i => i.json.url).filter(Boolean);
const merged = [...new Set([...seenUrls, ...newUrls])];
const fs = require('fs');
fs.writeFileSync('/home/n8n/uix-seen-urls.json', JSON.stringify({ seen: merged }, null, 2));
return [{ json: { updated: true, totalSeen: merged.length } }];
